import{_ as a,c as o,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Notas de Lançamento: Versões | Antigravity-Manager","description":"Aprenda método de versões do Antigravity-Manager. Confirme versão na página Settings e verifique atualizações, veja correções e avisos no README Changelog, use /healthz para verificar disponibilidade após atualização.","frontmatter":{"title":"Notas de Lançamento: Versões | Antigravity-Manager","sidebarTitle":"Entenda atualizações de versão em 3 minutos","subtitle":"Versões: baseadas em Changelog embutido no README","description":"Aprenda método de versões do Antigravity-Manager. Confirme versão na página Settings e verifique atualizações, veja correções e avisos no README Changelog, use /healthz para verificar disponibilidade após atualização.","tags":["changelog","lançamento","upgrade","solução de problemas"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":1},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}'),i={name:"pt/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function s(n,e,d,l,c,u){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="versoes-baseadas-em-changelog-embutido-no-readme" tabindex="-1">Versões: baseadas em Changelog embutido no README <a class="header-anchor" href="#versoes-baseadas-em-changelog-embutido-no-readme" aria-label="Permalink to &quot;Versões: baseadas em Changelog embutido no README&quot;">​</a></h1><p>Você prepara atualizar Antigravity Tools, o que mais teme não é &quot;não atualizou&quot;, mas &quot;atualizou só descobrir que há mudanças de compatibilidade&quot;. Esta página deixa claro método de leitura de <strong>Antigravity Tools Changelog (versões)</strong>, permitindo que você antes de atualizar julgue: esta atualização afetará o quê.</p><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O que você poderá fazer após concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O que você poderá fazer após concluir&quot;">​</a></h2><ul><li>Na página About de Settings, confirmar rapidamente versão atual, verificar atualização e obter entrada de download</li><li>No README do Changelog, só ler parágrafos de versão que afetam você (não precisa ler do início ao fim)</li><li>Antes de atualizar, fazer uma coisa: confirmar se há avisos de &quot;precisa modificar configuração/mapeamento de modelo manualmente&quot;</li><li>Após atualizar, fazer verificação mínima (<code>/healthz</code>) para confirmar que proxy ainda funciona</li></ul><h2 id="o-que-e-changelog" tabindex="-1">O que é Changelog? <a class="header-anchor" href="#o-que-e-changelog" aria-label="Permalink to &quot;O que é Changelog?&quot;">​</a></h2><p><strong>Changelog</strong> é lista que registra &quot;o que mudou desta vez&quot; por versão. Antigravity Tools escrevem diretamente em &quot;Versões&quot; do README, cada versão marcará data e mudanças-chave. Antes de atualizar, primeiro ver Changelog pode reduzir probabilidade de encontrar mudanças de compatibilidade ou problemas de regressão.</p><h2 id="quando-usar-esta-pagina" tabindex="-1">Quando usar esta página <a class="header-anchor" href="#quando-usar-esta-pagina" aria-label="Permalink to &quot;Quando usar esta página&quot;">​</a></h2><ul><li>Você prepara atualizar de versão antiga para nova, primeiro confirmar pontos de risco</li><li>Você encontra certo problema (como 429/0 Token/Cloudflared), quer confirmar se foi corrigido em versões recentes</li><li>Você mantém versão unificada em equipe, precisa dar a colegas método de &quot;ler mudanças por versão&quot;</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação antes de começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação antes de começar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Sugiro primeiro preparar caminho de atualização</p><p>Muitos métodos de instalação/atualização (brew, download manual de Releases, atualização no aplicativo). Se ainda não determinou qual caminho usar, primeiro veja <strong><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/installation.md" target="_blank" rel="noreferrer">Instalação e Atualização: melhor caminho de instalação de desktop (brew / releases)</a></strong>.</p></div><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-confirme-versao-atual-na-pagina-about" tabindex="-1">Passo 1: Confirme versão atual na página About <a class="header-anchor" href="#passo-1-confirme-versao-atual-na-pagina-about" aria-label="Permalink to &quot;Passo 1: Confirme versão atual na página About&quot;">​</a></h3><p><strong>Por que</strong> Changelog é organizado por versão. Você primeiro sabe versão atual, depois sabe &quot;a partir de onde começar a ler&quot;.</p><p>Caminho de operação: <strong>Settings</strong> → <strong>About</strong>.</p><p><strong>Você deve ver</strong>: Área de título da página mostra nome do aplicativo e número de versão (por exemplo <code>v3.3.49</code>).</p><h3 id="passo-2-clique-verificar-atualizacoes-obtenha-versao-mais-recente-e-entrada-de-download" tabindex="-1">Passo 2: Clique &quot;verificar atualizações&quot;, obtenha versão mais recente e entrada de download <a class="header-anchor" href="#passo-2-clique-verificar-atualizacoes-obtenha-versao-mais-recente-e-entrada-de-download" aria-label="Permalink to &quot;Passo 2: Clique &quot;verificar atualizações&quot;, obtenha versão mais recente e entrada de download&quot;">​</a></h3><p><strong>Por que</strong> Você precisa primeiro saber &quot;qual é número da versão mais recente&quot;, depois no Changelog escolher parágrafos de versão entre versões cruzadas.</p><p>Na página About, clique &quot;verificar atualizações&quot;.</p><p><strong>Você deve ver</strong>:</p><ul><li>Se houver atualização: exibe &quot;new version available&quot;, aparece botão de download (abre <code>download_url</code>)</li><li>Se já mais recente: exibe &quot;latest version&quot;</li></ul><h3 id="passo-3-va-ao-readme-do-changelog-e-so-veja-versoes-que-voce-cruzou" tabindex="-1">Passo 3: Vá ao README do Changelog e só veja versões que você cruzou <a class="header-anchor" href="#passo-3-va-ao-readme-do-changelog-e-so-veja-versoes-que-voce-cruzou" aria-label="Permalink to &quot;Passo 3: Vá ao README do Changelog e só veja versões que você cruzou&quot;">​</a></h3><p><strong>Por que</strong> Você só se preocupa com &quot;mudanças entre sua versão atual e versão mais recente&quot;, outras versões históricas podem primeiro pular.</p><p>Abra README, localize <strong>&quot;Versões (Changelog)&quot;</strong>, comece da versão mais recente e desça até ver sua versão atual.</p><p><strong>Você deve ver</strong>: Versões listadas no formato <code>vX.Y.Z (YYYY-MM-DD)</code>, cada versão tem agrupamento de descrição (como correções principais/aperfeiçoamentos de funcionalidade).</p><h3 id="passo-4-apos-atualizacao-faca-verificacao-minima" tabindex="-1">Passo 4: Após atualização, faça verificação mínima <a class="header-anchor" href="#passo-4-apos-atualizacao-faca-verificacao-minima" aria-label="Permalink to &quot;Passo 4: Após atualização, faça verificação mínima&quot;">​</a></h3><p><strong>Por que</strong> A primeira coisa após atualizar não é &quot;rodar cenários complexos&quot;, mas primeiro confirmar que proxy ainda pode iniciar normalmente, pode ser verificado por cliente.</p><p>Seguindo fluxo de <strong><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-and-first-client.md" target="_blank" rel="noreferrer">Iniciar proxy reverso local e conectar primeiro cliente (/healthz + configuração SDK)</a></strong>, pelo menos verifique <code>GET /healthz</code> uma vez.</p><p><strong>Você deve ver</strong>: <code>/healthz</code> retorna sucesso (usado para confirmar serviço disponível).</p><h2 id="resumo-de-versoes-recentes-do-readme" tabindex="-1">Resumo de versões recentes (do README) <a class="header-anchor" href="#resumo-de-versoes-recentes-do-readme" aria-label="Permalink to &quot;Resumo de versões recentes (do README)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Versão</th><th>Data</th><th>Pontos que você deve prestar atenção</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>Defesa de interrupção Thinking e 0 Token; remover <code>gemini-2.5-flash-lite</code> e avisar você substituir manualmente mapeamento personalizado; configuração de idioma/tema entra em vigor imediatamente; aprimoramento de painel de monitoramento; melhoria de compatibilidade OAuth</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Processo de segundo plano em modo silencioso no Windows (corrigiu cintilação de console)</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>Aprimoramento de mapeamento de parâmetros de geração de imagem (<code>size</code>/<code>quality</code>); suporte a túnel Cloudflared; correção de falha de início causada por conflito de merge; compressão de contexto progressiva de três camadas</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Como julgar rapidamente &quot;esta atualização me afetará&quot;</p><p>Priorize encontrar estes dois tipos de frases:</p><ul><li><strong>Aviso do usuário/você precisa modificar</strong>: como nomear explicitamente que modelo padrão foi removido, requer que você ajuste manualmente mapeamento personalizado</li><li><strong>Correção principal/correção de compatibilidade</strong>: como 0 Token, 429, cintilação Windows, falha de início etc. problemas que &quot;farão você não conseguir usar&quot;</li></ul></div><hr><h2 id="apendice-referencias-de-codigo-fonte" tabindex="-1">Apêndice: Referências de código-fonte <a class="header-anchor" href="#apendice-referencias-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referências de código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver localizações do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Conteúdo</th><th>Caminho do arquivo</th><th>Número da linha</th></tr></thead><tbody><tr><td>Changelog embutido no README (versões)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L324-L455" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>324-455</td></tr><tr><td>Página About exibe número de versão e botão &quot;verificar atualizações&quot;</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L821-L954" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>821-954</td></tr><tr><td>Página About &quot;verificar atualizações&quot; retorna estrutura de comando</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L187-L215" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>187-215</td></tr><tr><td>Notificação de atualização automática (download e reinício)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/UpdateNotification.tsx#L33-L96" target="_blank" rel="noreferrer"><code>src/components/UpdateNotification.tsx</code></a></td><td>33-96</td></tr><tr><td>Número da versão atual (metadados de compilação)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/package.json#L1-L4" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-4</td></tr></tbody></table></details>',34)])])}const g=a(i,[["render",s]]);export{p as __pageData,g as default};
